// Parse request — supports agent eval AND prompt eval
var body = $input.first().json.body || $input.first().json;
var agent = body.agent || '';
var promptName = body.prompt_name || '';
var task = body.task || '';
var testCases = body.test_cases || [];
var judges = body.judges || ['relevance', 'helpfulness'];
var model = body.model || $env.INFERENCE_DEFAULT_MODEL || 'qwen2.5:14b';
var temperature = body.temperature != null ? body.temperature : 0.3;
var lite = body.lite === true || body.lite === 'true';
var MLFLOW = $env.MLFLOW_TRACKING_URI || 'http://genai-mlflow.genai.svc.cluster.local';
var GATEWAY = $env.AGENT_GATEWAY_URL || 'http://genai-agent-gateway.genai.svc.cluster.local:8000';
var LITELLM = $env.LITELLM_URL || 'http://genai-litellm.genai.svc.cluster.local:4000';
var LITELLM_KEY = $env.LITELLM_API_KEY || '';
var judgeModel = body.judge_model || model;

if (!agent && !promptName) return [{json: {error: 'agent or prompt_name required', _status: 400}}];
if (!testCases.length) return [{json: {error: 'test_cases required', _status: 400}}];

var suiteName = agent ? (agent + (task ? '.' + task : '')) : promptName;

var items = testCases.map(function(tc, i) {
  var userMsg = '';
  var vars = tc.variables || {};

  if (promptName) {
    // Prompt mode: render template variables into a message
    // Template vars are passed as-is — LiteLLM gets them as user message
    var parts = [];
    for (var k in vars) { parts.push(k + ': ' + vars[k]); }
    userMsg = parts.join('\n');
  } else {
    // Agent mode: build message from variables
    var parts = [];
    for (var k in vars) { parts.push(k + ': ' + vars[k]); }
    userMsg = parts.join('\n');
    if (task) userMsg = '[Task: ' + task + ']\n' + userMsg;
  }

  // Determine call URL and body
  var callUrl, callBody;
  if (agent && !lite) {
    // Full agent mode: through agent-gateway
    callUrl = GATEWAY + '/v1/chat/completions';
    callBody = JSON.stringify({model: 'agent:' + agent, messages: [{role: 'user', content: userMsg}], stream: false});
  } else {
    // Lite mode or prompt mode: direct to LiteLLM
    callUrl = LITELLM + '/v1/chat/completions';
    callBody = JSON.stringify({model: model, messages: [{role: 'user', content: userMsg}], temperature: temperature, max_tokens: 2000});
  }

  return {json: {
    _index: i,
    _agent: agent,
    _prompt_name: promptName,
    _task: task,
    _suite: suiteName,
    _label: tc.label || ('case_' + i),
    _user_message: userMsg,
    _variables: vars,
    _validators: tc.validators || [],
    _judges: judges,
    _judge_model: judgeModel,
    _model: model,
    _lite: lite,
    _call_url: callUrl,
    _call_body: callBody,
    _litellm_url: LITELLM + '/v1/chat/completions',
    _litellm_key: LITELLM_KEY,
    _mlflow_url: MLFLOW + '/api/2.0/mlflow',
    _experiment_name: suiteName + '-eval',
    _start_ts: Date.now()
  }};
});

return items;

// Parse agent-gateway response — NO HTTP calls
var plan = $('Error Gate').first().json;  // Won't work in loop, use item pairing
var item = $input.item.json;
var latencyMs = Date.now() - ($json._start_ts || Date.now());

// Get the plan data passed through
var allPlans = $('Eval Planner').all();
var idx = $itemIndex;
var planItem = allPlans[idx] ? allPlans[idx].json : {};

var responseText = '';
try {
  var choices = item.choices || [];
  if (choices.length > 0) {
    var content = choices[0].message.content;
    try {
      var inner = JSON.parse(content);
      responseText = inner.response || content;
    } catch(e) {
      responseText = content;
    }
  }
} catch(e) {
  responseText = JSON.stringify(item).substring(0, 500);
}

// Run validators
var validators = planItem._validators || [];
var passed = true;
var failReasons = [];
var rt = responseText.trim();
var rtl = rt.toLowerCase();

for (var v of validators) {
  if (v.type === 'expect_contains' && rtl.indexOf(v.value.toLowerCase()) === -1) {
    passed = false; failReasons.push('missing: ' + v.value);
  }
  if (v.type === 'expect_min_length' && rt.length < v.value) {
    passed = false; failReasons.push(rt.length + ' chars < ' + v.value);
  }
  if (v.type === 'expect_max_words' && rt.split(/\s+/).length > v.value) {
    passed = false; failReasons.push(rt.split(/\s+/).length + ' words > ' + v.value);
  }
  if (v.type === 'expect_json_keys') {
    try {
      var obj = JSON.parse(rt.indexOf('```') >= 0 ? rt.split('```')[1].replace(/^json/, '') : rt);
      var missing = v.value.filter(function(k) { return !(k in obj); });
      if (missing.length) { passed = false; failReasons.push('missing keys: ' + missing.join(',')); }
    } catch(e) { passed = false; failReasons.push('invalid JSON'); }
  }
}

return {json: {
  index: idx,
  label: planItem._label || ('case_' + idx),
  agent: planItem._agent || '',
  task: planItem._task || '',
  response: responseText,
  latency_ms: latencyMs,
  passed: passed,
  fail_reasons: failReasons,
  status: passed ? 'PASS' : 'FAIL',
  _judges: planItem._judges || [],
  _judge_model: planItem._judge_model || '',
  _litellm_url: planItem._litellm_url || '',
  _litellm_key: planItem._litellm_key || '',
  _mlflow_url: planItem._mlflow_url || '',
  _experiment_name: planItem._experiment_name || '',
  _user_message: planItem._user_message || '',
  _judge_body: JSON.stringify({
    model: planItem._judge_model || 'qwen2.5:14b',
    messages: [{role: 'user', content: 'Rate this AI response on: ' + (planItem._judges || []).join(', ') + '.\nQuestion: ' + (planItem._user_message || '').substring(0, 500) + '\nResponse: ' + responseText.substring(0, 1000) + '\nReturn JSON only: {"scores": {"criterion": {"score": 0.0-1.0, "reason": "one sentence"}}}'}],
    temperature: 0,
    max_tokens: 1000
  })
}};

// Assemble final results from all test cases — NO HTTP calls
var parseResults = $('Parse Response').all();
var judgeResults = $input.all();
var results = [];
var totalLatency = 0;
var passCount = 0;
var avgScores = {};
var scoreCount = 0;

for (var i = 0; i < parseResults.length; i++) {
  var pr = parseResults[i].json;
  var jr = judgeResults[i] ? judgeResults[i].json : {};

  // Parse judge scores
  var scores = {};
  try {
    var judgeContent = jr.choices ? jr.choices[0].message.content : '';
    var parsed = JSON.parse(judgeContent.indexOf('```') >= 0 ? judgeContent.split('```')[1].replace(/^json/, '') : judgeContent);
    scores = parsed.scores || parsed;
    for (var k in scores) {
      var s = typeof scores[k] === 'object' ? scores[k].score : scores[k];
      if (!avgScores[k]) avgScores[k] = {total: 0, count: 0};
      avgScores[k].total += (s || 0);
      avgScores[k].count += 1;
    }
    scoreCount++;
  } catch(e) {
    scores = {parse_error: e.message};
  }

  totalLatency += pr.latency_ms || 0;
  if (pr.passed) passCount++;

  results.push({
    label: pr.label,
    agent: pr.agent,
    task: pr.task,
    status: pr.status,
    response: pr.response.substring(0, 500),
    latency_ms: pr.latency_ms,
    scores: scores,
    fail_reasons: pr.fail_reasons
  });
}

var summary = {
  total_cases: results.length,
  passed: passCount,
  failed: results.length - passCount,
  avg_latency_ms: results.length > 0 ? Math.round(totalLatency / results.length) : 0,
  avg_scores: {}
};

for (var k in avgScores) {
  summary.avg_scores[k] = Math.round((avgScores[k].total / avgScores[k].count) * 100) / 100;
}

return [{json: {results: results, summary: summary}}];
